def all_prefixes(string: str) -> List[str]:
    """ Return list of all prefixes from shortest to longest of the input string
    >>> all_prefixes('abc')
    ['a', 'ab', 'abc']
    """
    if string == '':
        return ['']
    elif len(string) == 1:
        return ['', string]
    else:
        pre, suf = all_prefixes(string[:-1])
        return ['', pre+suf]

