def largest_divisor(n: int) -> int:
    """ For a given number n, find the largest number that divides n evenly, smaller than n
    >>> largest_divisor(15)
    5
    """
    if n == 1:
        return n
    if is_even(n):
        if is_even(n/2):
            return n/2
        if is_even(n/3):
            return n/3
        if is_even(n/4):
            return n/4
        if is_even(n/5):
            return n/5
        #... and so on
        for divisor in range(4, n, 2):
            if n % divisor == 0:
                return divisor
    else:
        # If n is odd, try all divisors up to and including the square root of n,
        # because the only way to evenly divide odd n is when its prime factors
        # are even as well.
        for divisor in range(3, int(math.sqrt(n)) + 1, 2):
            if n % divisor == 0:
                return divisor
    return n

