def minSubArraySum(nums):
    """
    Given an array of integers nums, find the minimum sum of any non-empty sub-array
    of nums.
    Example
    minSubArraySum([2, 3, 4, 1, 2, 4]) == 1
    minSubArraySum([-1, -2, -3]) == -6
    """
    if len(nums) == 1:
        return nums[0]
    if len(nums) == 2:
        if nums[0] > 0:
            return nums[0]
        else:
            return max(nums)
    min_so_far = None
    min_ending_here = None
    for n in nums:
        if min_ending_here is None:
            min_ending_here = n
        else:
            min_ending_here = min_ending_here + n
        if min_so_far is None or min_ending_here < min_so_far:
            min_so_far = min_ending_here
    return min_so_far

def minSubArraySum(nums):
    """
    Given an array of integers nums, find the minimum sum of any non-empty sub-array
    of nums.
    Example
    minSubArraySum([2, 3, 4, 1, 2, 4]) == 1
    minSubArraySum([-1, -2, -3]) == -6
    """
    if len(nums) <= 1:
        return min(nums)
    total, curr = nums[0], 0
    for num in nums[1:]:
        if curr + num > num:
            curr += num
        else:
            curr = num
        total = min(curr, total)
    return total

